<?php require __DIR__.'/../includes/bootstrap.php';require_auth();$id=(int)($_GET['id']??0);$s=db()->prepare('SELECT b.*,c.name company_name FROM brands b JOIN companies c ON c.id=b.company_id WHERE b.id=?');$s->execute([$id]);$b=$s->fetch();if(!$b){http_response_code(404);exit('Brand not found.');}if(!can_manage_brand($b)){http_response_code(403);exit('Brand manager or company owner access required.');}app_header('Brand Dashboard');?><section class="dashboard-hero"><p class="eyebrow">BRAND MANAGEMENT</p><h1><?=e($b['name'])?></h1><p>Parent company: <?=e($b['company_name'])?></p></section><section class="dashboard-grid"><article class="app-card"><h2>Status</h2><p><span class="status-badge <?=e($b['status'])?>"><?=e(ucfirst($b['status']))?></span></p><p><?=e($b['review_notes'])?></p></article><article class="app-card"><h2>Brand Profile</h2><p><a class="button primary" href="edit.php?id=<?=$id?>">Edit Brand</a> <a class="button ghost" href="view.php?slug=<?=urlencode($b['slug'])?>">View Profile</a></p></article></section><?php app_footer();
